import React from 'react';
import { createRoot } from 'react-dom/client';
import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { createClient } from '@supabase/supabase-js';
import { validateProjectObject } from './features/rules/rulesEngine';
import { buildTechnicalList, formatTechnicalList } from './features/technicalList/buildTechnicalList';
import { buildMdfCutPlan, formatMdfCutPlan } from './features/cnc/buildMdfCutPlan';
import { PROJECT_TEMPLATES } from './features/templates/templatesData';
