type AppMode = 'store' | 'factory' | 'admin';
type UserRole = 'store' | 'factory';
type LeftPanel = 'templates' | 'adjustments' | 'project' | 'factory';
type LoginState = { role: UserRole; email: string; name: string };
type ProductDraft = { codigo: string; nome: string; categoria: string; unidade: string; custo_fallback: number; preco_fallback: number | null; observacoes: string };
type Config = { h: number; w: number; d: number; mdf: number; shelves: number; doors: number; margin: number; profile: string; glass: string; hinge: string };
type Amb = { w: number; d: number; h: number; floor: string; back: boolean; left: boolean; right: boolean };
type WindowData = { w: number; h: number; fromFloor: number; glass: boolean; frame: boolean; opening: string };
type CounterData = { w: number; d: number; thick: number; fromFloor: number; wetW: number; depthFromWall: number; sink: boolean; faucet: boolean };
type ClosetData = { w: number; d: number; h: number; modules: number; shelves: number; sideType: string; backGlass: boolean; doors: boolean; led: boolean };
type ObjBase = { id: string; type: 'window' | 'countertop' | 'closet' | 'cristaleira'; name: string; x: number; y: number; z: number; rotation: number; visible: boolean; locked: boolean };
type WinObj = ObjBase & { type: 'window'; data: WindowData };
type CounterObj = ObjBase & { type: 'countertop'; data: CounterData };
type ClosetObj = ObjBase & { type: 'closet'; data: ClosetData };
type CristObj = ObjBase & { type: 'cristaleira'; data: Config };
type ProjectObject = WinObj | CounterObj | ClosetObj | CristObj;
type ParamRow = { id: string; estrutura_slug: string; grupo: string; chave: string; nome: string; tipo: 'number' | 'text' | 'boolean' | 'select'; unidade: string | null; valor_num: number | null; valor_text: string | null; valor_bool: boolean | null; opcoes: any; descricao: string | null; ordem: number; editavel: boolean };
type ColorProfile = { id: string; nome: string; custo: number | null; margem: number | null; perda: number | null; preco: number | null; insumos: string[] | null; tipologias: string[] | null; tags: string[] | null };
type ColorMaterial = { id: number; nome: string | null; custo: number | null; tipo_medida: string | null; margem: number | null; preco: number | null; perda: number | null; tag: string | null };
type CatalogItem = { id: string; codigo: string; nome: string; categoria: string; unidade: string; custo_fallback: number; preco_fallback: number | null; perda_percentual: number; margem_percentual: number | null; fornecedor: string | null; cores: string[]; produtos_compativeis: string[]; observacoes: string | null; color_search_terms: string[]; ativo: boolean };
type RuleMsg = { severity: 'info' | 'warning' | 'error'; code: string; title: string; message: string; target?: string };

const MOBIL_URL = (import.meta as any).env?.VITE_SUPABASE_URL || 'https://uyssmueddxtylajnmxad.supabase.co';
const MOBIL_KEY = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY || 'sb_publishable_YVwgZbFAqi5M4N1i-Iwgdg_7GTzwxrw';
const COLOR_URL = (import.meta as any).env?.VITE_COLOR_SUPABASE_URL || 'https://hfhwvzldhgqniqnurync.supabase.co';
const COLOR_KEY = (import.meta as any).env?.VITE_COLOR_SUPABASE_ANON_KEY || 'sb_publishable_0j-jqB63odD2yvugj7olMA_s18OwuPl';
const supabase = createClient(MOBIL_URL, MOBIL_KEY);
const colorDb = createClient(COLOR_URL, COLOR_KEY);
const gp: Record<string, number> = { incolor: 120, espelho_prata: 180, reflecta_bronze: 230, reflecta_prata: 220, fume: 170 };
const fallback: Record<string, number | boolean> = { cristaleira_altura_padrao: 2200, cristaleira_largura_padrao: 1000, cristaleira_profundidade_padrao: 450, cristaleira_mdf_padrao: 18, cristaleira_prateleiras_padrao: 4, cristaleira_portas_padrao: 2, cristaleira_margem_padrao: 45, mdf_preco_m2: 115, curva_desconta_mdf: false, curva_desconto_altura: 0, curva_desconto_largura: 0, curva_desconto_por_porta: 1.5, reta_desconta_mdf: true, reta_desconto_altura: 3, reta_desconto_largura: 3, reta_desconto_por_porta: 1.5, porta_perda_percentual: 10, porta_mao_obra: 35, porta_kit_montagem: 4.84, baguete_preco_m: 1.2, vidro_espessura_padrao: 4 };
const defaultCrist: Config = { h: 2200, w: 1000, d: 450, mdf: 18, shelves: 4, doors: 2, margin: 45, profile: '', glass: 'reflecta_bronze', hinge: 'curva' };
const modeTitles: Record<AppMode, string> = { store: 'Loja', factory: 'Fábrica', admin: 'Técnico' };
const roleTitles: Record<UserRole, string> = { store: 'Loja', factory: 'Fábrica' };

function n(rows: ParamRow[], key: string) { const v = rows.find(x => x.chave === key)?.valor_num; return Number(v ?? fallback[key] ?? 0) }
function b(rows: ParamRow[], key: string) { const v = rows.find(x => x.chave === key)?.valor_bool; return Boolean(v ?? fallback[key] ?? false) }
function brl(x: number) { return `R$ ${x.toFixed(2)}` }
function ruleIcon(s: string) { return s === 'error' ? '❌' : s === 'warning' ? '⚠' : 'ℹ' }
function catalogForRules(catalog: CatalogItem[]) { return catalog.map(i => ({ codigo: i.codigo, nome: i.nome, categoria: i.categoria, unidade: i.unidade, custo_fallback: i.custo_fallback, produtos_compativeis: i.produtos_compativeis })) }
function mat(materials: ColorMaterial[], term: string) { return materials.find(m => (m.nome || '').toLowerCase().includes(term.toLowerCase())) }
function calc(c: Config, rows: ParamRow[], profiles: ColorProfile[], materials: ColorMaterial[]) { const prefix = c.hinge === 'reta' ? 'reta' : 'curva'; const discountMdf = b(rows, `${prefix}_desconta_mdf`); const baseW = c.w - (discountMdf ? c.mdf * 2 : 0), baseH = c.h - (discountMdf ? c.mdf * 2 : 0); const hingeW = n(rows, `${prefix}_desconto_largura`), hingeH = n(rows, `${prefix}_desconto_altura`), gap = n(rows, `${prefix}_desconto_por_porta`); const perda = 1 + n(rows, 'porta_perda_percentual') / 100; const dw = ((baseW - hingeW) / Math.max(1, c.doors)) - (c.doors > 1 ? gap : 0); const dh = baseH - hingeH; const uw = c.w - c.mdf * 2, uh = c.h - c.mdf * 2; const selected = profiles.find(p => p.id === c.profile); const profileCost = Number(selected?.custo ?? 19); const ba02 = Number(mat(materials, 'BA02')?.custo ?? n(rows, 'baguete_preco_m')); const cant = Number(mat(materials, 'cantoneira')?.custo ?? n(rows, 'porta_kit_montagem')); const ga = (dw / 1000) * (dh / 1000) * c.doors * perda; const pm = ((dw / 1000) * 2 + (dh / 1000) * 2) * c.doors * perda; const ma = (c.h / 1000 * c.d / 1000 * 2) + (c.w / 1000 * c.d / 1000 * 2) + (uw / 1000 * (c.d - c.mdf) / 1000 * c.shelves); const cost = ga * gp[c.glass] + pm * profileCost + ma * n(rows, 'mdf_preco_m2') + pm * ba02 + c.doors * 4 * cant + c.doors * n(rows, 'porta_mao_obra') + 80; return { uw, uh, baseW, baseH, dw, dh, ga, pm, ma, cost, sale: cost / (1 - c.margin / 100), sideGap: gap / 2, displayGap: gap, profileCost, ba02, cant, profileName: selected?.nome || '1036 padrão' } }
function closetCalc(c: ClosetData) { const mw = c.w / Math.max(c.modules, 1); const profiles = (c.modules + 1) * c.h / 1000 + 2 * ((c.w / 1000) * 2 + (c.d / 1000) * 2) + c.modules * c.shelves * (mw / 1000); const glass = (c.backGlass ? c.w / 1000 * c.h / 1000 : 0) + 2 * (c.d / 1000 * c.h / 1000) + (c.doors ? c.w / 1000 * c.h / 1000 : 0); return { mw, totalProfile: profiles, glassArea: glass } }
function closetRules(c: ClosetData, catalog: CatalogItem[]) { return validateProjectObject({ type: 'closet_evidence', width: c.w, depth: c.d, height: c.h, modules: c.modules, shelves: c.shelves, sideType: c.sideType, backGlass: c.backGlass, doors: c.doors, led: c.led, glassThickness: 4, catalog: catalogForRules(catalog) }) }
function doorRules(c: Config, rows: ParamRow[], catalog: CatalogItem[], profiles: ColorProfile[]) { const prefix = c.hinge === 'reta' ? 'reta' : 'curva'; const profileName = profiles.find(p => p.id === c.profile)?.nome || '1036'; const profileCode = (profileName.match(/1036|070|3545|3446/) || ['1036'])[0]; return validateProjectObject({ type: 'porta_aluminio', height: c.h, width: c.w, doors: c.doors, hinge: c.hinge, mdfThickness: c.mdf, discountMdf: b(rows, `${prefix}_desconta_mdf`), discountHeight: n(rows, `${prefix}_desconto_altura`), discountWidth: n(rows, `${prefix}_desconto_largura`), gapPerDoor: n(rows, `${prefix}_desconto_por_porta`), profileCode, catalog: catalogForRules(catalog) }) }
function make(type: ProjectObject['type'], name: string, data: any): ProjectObject { return { id: `${type}-${Date.now()}-${Math.round(Math.random() * 999)}`, type, name, x: 0, y: 0, z: 0, rotation: 0, visible: true, locked: false, data } as ProjectObject }
function dims(o: ProjectObject) { if (o.type === 'window') return { w: o.data.w, d: 30 }; if (o.type === 'countertop') return { w: o.data.w, d: o.data.d }; if (o.type === 'closet') return { w: o.data.w, d: o.data.d }; return { w: o.data.w, d: o.data.d } }
function loadAuth(): LoginState | null { try { const raw = localStorage.getItem('mobil-auth'); return raw ? JSON.parse(raw) as LoginState : null } catch { return null } }

function App() {
 const [auth, setAuth] = React.useState<LoginState | null>(loadAuth);
 const [appMode, setAppMode] = React.useState<AppMode>('store');
 const [activePanel, setActivePanel] = React.useState<LeftPanel>('templates');
 const [amb, setAmb] = React.useState<Amb>({ w: 3200, d: 2800, h: 2700, floor: 'porcelanato claro', back: true, left: true, right: false });
 const [objects, setObjects] = React.useState<ProjectObject[]>([]); const [selectedId, setSelectedId] = React.useState<string | null>('environment');
 const [rows, setRows] = React.useState<ParamRow[]>([]); const [catalog, setCatalog] = React.useState<CatalogItem[]>([]); const [profiles, setProfiles] = React.useState<ColorProfile[]>([]); const [materials, setMaterials] = React.useState<ColorMaterial[]>([]);
 const [status, setStatus] = React.useState('Carregando parâmetros...'); const [colorStatus, setColorStatus] = React.useState('Carregando ColorGlass...'); const [catalogStatus, setCatalogStatus] = React.useState('Carregando catálogo técnico...');
 const [menuOpen, setMenuOpen] = React.useState(true); const [resultadoOpen, setResultadoOpen] = React.useState(true); const colorLoaded = React.useRef(false);
 React.useEffect(() => { if (auth?.role === 'store') { if (appMode !== 'store') setAppMode('store'); if (activePanel === 'factory') setActivePanel('templates') } }, [auth, appMode, activePanel]);
 React.useEffect(() => { supabase.from('promob_parametros').select('*').order('estrutura_slug').order('ordem').then(({ data, error }) => { if (error) setStatus('Erro ao carregar parâmetros. Usando padrão local.'); else { setRows((data || []) as ParamRow[]); setStatus('Parâmetros conectados ao Supabase.') } }) }, []);
 React.useEffect(() => { supabase.from('mobil_catalog_itens').select('*').eq('ativo', true).order('categoria').order('codigo').then(({ data, error }) => { if (error) setCatalogStatus('Erro ao carregar catálogo técnico.'); else { setCatalog((data || []) as CatalogItem[]); setCatalogStatus(`Catálogo técnico MOBIL: ${(data || []).length} itens carregados.`) } }) }, []);
 React.useEffect(() => { Promise.all([colorDb.from('perfis').select('id,nome,custo,margem,perda,preco,insumos,tipologias,tags').order('nome'), colorDb.from('materiais').select('id,nome,custo,tipo_medida,margem,preco,perda,tag').order('nome')]).then(([p, m]) => { if (p.error || m.error) { setColorStatus('Erro ao ler ColorGlass. Usando fallback.'); return } const prof = (p.data || []) as ColorProfile[]; const mats = ((m.data || []) as ColorMaterial[]).filter(x => { const z = (x.nome || '').toLowerCase(); return z.includes('ba02') || z.includes('cantoneira') || z.includes('baguete') || z.includes('conector') || z.includes('957') || z.includes('956') }); setProfiles(prof); setMaterials(mats); setColorStatus(`ColorGlass conectado em leitura: ${prof.length} perfis e ${mats.length} materiais lidos.`); if (!colorLoaded.current && prof[0]) { colorLoaded.current = true; setObjects(os => os.map(o => o.type === 'cristaleira' ? { ...o, data: { ...o.data, profile: prof.find(p => (p.nome || '').includes('1036'))?.id || prof[0].id } } : o)) } }) }, []);
 const selected = selectedId === 'environment' ? null : objects.find(o => o.id === selectedId) || null; const tech = buildTechnicalList({ objects, rows, catalog, profiles, materials, margin: 45 }); const cut = buildMdfCutPlan({ objects, rows });
 const updateObj = (id: string, patch: any) => setObjects(os => os.map(o => o.id === id ? { ...o, ...patch } as ProjectObject : o)); const updateData = (id: string, patch: any) => setObjects(os => os.map(o => o.id === id ? { ...o, data: { ...o.data, ...patch } } as ProjectObject : o));
 const applyReadyTemplate = (template: ProjectTemplate, replaceEnvironment: boolean) => { const result = applyTemplate(template, { environment: amb, objects }, { replaceEnvironment, clearObjects: replaceEnvironment, centerObjects: false }); if (result.environment) setAmb(result.environment as Amb); setObjects(result.objects as ProjectObject[]); setSelectedId(result.selectedObjectId); setResultadoOpen(true); setActivePanel('adjustments') };
 const add = (o: ProjectObject) => { setObjects(os => [...os, o]); setSelectedId(o.id); setActivePanel('adjustments') }; const addWindow = () => add({ ...make('window', 'Janela', { w: 1200, h: 1000, fromFloor: 900, glass: true, frame: true, opening: 'fixa' }), z: -amb.d / 2 + 35 } as ProjectObject); const addCounter = () => add(make('countertop', 'Bancada / área molhada', { w: 2400, d: 600, thick: 20, fromFloor: 900, wetW: 800, depthFromWall: 40, sink: true, faucet: true })); const addCloset = () => add(make('closet', 'Closet Evidence', { w: 2600, d: 520, h: 2400, modules: 4, shelves: 3, sideType: '9577 externo', backGlass: true, doors: true, led: true })); const addCrist = () => add(make('cristaleira', 'Cristaleira', { ...defaultCrist, h: n(rows, 'cristaleira_altura_padrao') || 2200, w: n(rows, 'cristaleira_largura_padrao') || 1000, d: n(rows, 'cristaleira_profundidade_padrao') || 450, mdf: n(rows, 'cristaleira_mdf_padrao') || 18, shelves: n(rows, 'cristaleira_prateleiras_padrao') || 4, doors: n(rows, 'cristaleira_portas_padrao') || 2, margin: n(rows, 'cristaleira_margem_padrao') || 45, profile: profiles.find(p => (p.nome || '').includes('1036'))?.id || '' }));
 const remove = () => { if (selected) { setObjects(os => os.filter(o => o.id !== selected.id)); setSelectedId('environment') } }; const duplicate = () => { if (selected) add({ ...selected, id: `${selected.type}-${Date.now()}`, name: `${selected.name} cópia`, x: selected.x + 120, data: { ...selected.data } } as ProjectObject) }; const movePreset = (mode: string) => { if (!selected) return; const d = dims(selected); if (mode === 'center') updateObj(selected.id, { x: 0, z: 0 }); if (mode === 'back') updateObj(selected.id, { z: -amb.d / 2 + d.d / 2 + 40 }); if (mode === 'left') updateObj(selected.id, { x: -amb.w / 2 + d.w / 2 + 40 }); if (mode === 'right') updateObj(selected.id, { x: amb.w / 2 - d.w / 2 - 40 }) };
 const saveRows = async () => { if (auth?.role !== 'factory') return setStatus('Apenas fábricas podem alterar parâmetros.'); setStatus('Salvando parâmetros...'); const payload = rows.map(({ id, created_at, updated_at, ...x }: any) => x); const { error } = await supabase.from('promob_parametros').upsert(payload, { onConflict: 'chave' }); setStatus(error ? 'Erro ao salvar parâmetros.' : 'Parâmetros salvos no Supabase.') };
 const addCatalogItem = async (draft: ProductDraft) => { if (auth?.role !== 'factory') { setCatalogStatus('Apenas fábricas podem cadastrar produtos.'); return } const payload = { codigo: draft.codigo.trim(), nome: draft.nome.trim(), categoria: draft.categoria.trim() || 'produto', unidade: draft.unidade.trim() || 'un', custo_fallback: Number(draft.custo_fallback || 0), preco_fallback: draft.preco_fallback == null ? null : Number(draft.preco_fallback), perda_percentual: 0, margem_percentual: null, fornecedor: 'MOBIL', cores: [], produtos_compativeis: ['cristaleira', 'closet', 'bancada'], observacoes: draft.observacoes || null, color_search_terms: [draft.codigo, draft.nome].filter(Boolean), ativo: true }; const localItem = { id: `local-${Date.now()}`, ...payload } as CatalogItem; setCatalogStatus('Salvando produto no catálogo...'); const { data, error } = await supabase.from('mobil_catalog_itens').insert(payload).select('*').single(); if (error) { setCatalog(c => [...c, localItem]); setCatalogStatus('Produto criado localmente nesta sessão. Supabase bloqueou o insert.'); return } setCatalog(c => [...c, data as CatalogItem]); setCatalogStatus('Produto cadastrado no catálogo técnico MOBIL.') };
 const login = (next: LoginState) => { localStorage.setItem('mobil-auth', JSON.stringify(next)); setAuth(next); setAppMode(next.role === 'factory' ? 'factory' : 'store'); setActivePanel('templates') };
 const logout = async () => { await supabase.auth.signOut().catch(() => null); localStorage.removeItem('mobil-auth'); setAuth(null); setAppMode('store'); setActivePanel('templates') };
 if (!auth) return <LoginScreen onLogin={login} />;
 const canManage = auth.role === 'factory';
 return <main className={`app mode-${appMode}`} style={{ gridTemplateColumns: `${menuOpen ? 430 : 64}px 1fr ${resultadoOpen ? 420 : 64}px` }}><aside className="side leftSide"><button className="flag" onClick={() => setMenuOpen(!menuOpen)}>MOBIL</button>{menuOpen && <div className="sideBody"><AuthBar auth={auth} onLogout={logout} /><ModeSwitcher mode={appMode} setMode={setAppMode} role={auth.role} /><ModeHelp mode={appMode} /><PanelNav panel={activePanel} setPanel={setActivePanel} canManage={canManage} /><div className="workPanel">{activePanel === 'templates' && <div className="panelStack"><SectionHero title="Templates prontos" eyebrow="Comece por modelos" text="Escolha um ambiente/produto pronto e depois ajuste medidas e materiais." /><TemplatePanel templates={PROJECT_TEMPLATES} onAdd={t => applyReadyTemplate(t, false)} onReplace={t => applyReadyTemplate(t, true)} /><div className="quickCreate"><h3>Adicionar estrutura manualmente</h3><button className="addBtn" onClick={addCounter}>Bancada / área molhada +</button><button className="addBtn" onClick={addCloset}>Closet Evidence +</button><button className="addBtn" onClick={addCrist}>Cristaleira +</button><button className="addBtn" onClick={addWindow}>Janela +</button></div></div>}{activePanel === 'adjustments' && <div className="panelStack"><SectionHero title="Ajustes do projeto" eyebrow="Medidas e propriedades" text="Edite o ambiente e o objeto selecionado. Essa é a área principal da loja." /><AmbienteForm amb={amb} setAmb={setAmb} addWindow={addWindow} /><ObjectProps selectedId={selectedId} selected={selected} amb={amb} setAmb={setAmb} updateObj={updateObj} updateData={updateData} duplicate={duplicate} remove={remove} movePreset={movePreset} catalog={catalog} profiles={profiles} materials={materials} rows={rows} /></div>}{activePanel === 'project' && <div className="panelStack"><SectionHero title="Projeto atual" eyebrow="Organização" text="Selecione objetos, confira o que está visível e use a navegação 3D." /><ObjectList objects={objects} selectedId={selectedId} setSelectedId={setSelectedId} /><div className="helpBox"><b>Navegação 3D</b><span>Scroll: zoom</span><span>Botão esquerdo: girar</span><span>Botão direito: mover</span></div></div>}{activePanel === 'factory' && canManage && <div className="panelStack"><SectionHero title="Área da fábrica" eyebrow="Produtos e regras" text="Cadastre produtos, revise catálogo técnico e altere parâmetros de produção." /><ProductRegistrationPanel onCreate={addCatalogItem} status={catalogStatus} /><CatalogPanel catalog={catalog} profiles={profiles} materials={materials} status={catalogStatus} /><Parametros rows={rows} setRows={setRows} saveRows={saveRows} status={status} /></div>}{activePanel === 'factory' && !canManage && <div className="panelStack"><SectionHero title="Área da fábrica" eyebrow="Acesso restrito" text="Esse painel é exclusivo para fabricantes." /><div className="lockedNotice">Acesso Loja: use modelos prontos e adapte medidas. Produtos, custos e parâmetros são gerenciados pela fábrica.</div></div>}</div></div>}</aside><section className="workspace"><div className="scene"><Canvas camera={{ position: [2.8, 2, 3.5], fov: 45 }} onPointerMissed={() => setSelectedId(null)}><ambientLight intensity={.85} /><directionalLight position={[3, 4, 5]} /><Env3D amb={amb} selected={selectedId === 'environment'} onSelect={() => setSelectedId('environment')} />{objects.map(o => <Object3D key={o.id} obj={o} selected={selectedId === o.id} onSelect={() => setSelectedId(o.id)} amb={amb} rows={rows} profiles={profiles} materials={materials} />)}<OrbitControls /></Canvas>{objects.length === 0 && <div className="canvasHint"><h2>Escolha um template</h2><p>Abra a aba Templates na lateral esquerda para começar com modelos prontos.</p></div>}</div></section><aside className="side rightSide"><button className="flag rightFlag" onClick={() => setResultadoOpen(!resultadoOpen)}>{auth.role === 'store' ? 'Resultado Loja' : modeTitles[appMode]}</button>{resultadoOpen && <Resultado mode={appMode} amb={amb} objects={objects} rows={rows} profiles={profiles} materials={materials} catalog={catalog} colorStatus={colorStatus} catalogStatus={catalogStatus} tech={tech} cut={cut} />}</aside></main>
}
function LoginScreen({ onLogin }: { onLogin: (s: LoginState) => void }) { const [role, setRole] = React.useState<UserRole>('store'); const [email, setEmail] = React.useState(''); const [password, setPassword] = React.useState(''); const [name, setName] = React.useState(''); const [loading, setLoading] = React.useState(false); const [msg, setMsg] = React.useState(''); const submit = async (e: React.FormEvent) => { e.preventDefault(); if (!email || password.length < 4) { setMsg('Informe email e senha com pelo menos 4 caracteres.'); return } setLoading(true); setMsg('Validando acesso...'); try { const { data, error } = await supabase.auth.signInWithPassword({ email, password }); if (error) { const created = await supabase.auth.signUp({ email, password, options: { data: { role, name: name || undefined } } }); if (created.error) throw created.error } else { const remoteRole = data.user?.user_metadata?.role as UserRole | undefined; if ((remoteRole === 'store' || remoteRole === 'factory') && remoteRole !== role) { setMsg(`Este email pertence ao sistema ${roleTitles[remoteRole]}. Troque o portal de entrada.`); setLoading(false); return } } onLogin({ role, email, name: name || email.split('@')[0] }) } catch (err: any) { setMsg(`Supabase não liberou o acesso: ${err?.message || 'erro desconhecido'}. Use demonstração para testar o MVP.`) } finally { setLoading(false) } }; return <div className="loginShell"><form className="loginCard" onSubmit={submit}><h1>MOBIL</h1><p>Escolha o portal correto. Loja adapta modelos para projetos; Fábrica gerencia produtos, parâmetros e produção.</p><div className="loginTabs"><button type="button" className={role === 'store' ? 'active' : ''} onClick={() => setRole('store')}>Loja</button><button type="button" className={role === 'factory' ? 'active' : ''} onClick={() => setRole('factory')}>Fábrica</button></div><label>Nome / empresa<input value={name} onChange={e => setName(e.target.value)} placeholder={role === 'store' ? 'Loja parceira' : 'Fábrica'} /></label><label>Email<input value={email} onChange={e => setEmail(e.target.value)} placeholder="email@empresa.com" /></label><label>Senha<input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="mínimo 4 caracteres" /></label><div className="loginActions"><button className="loginPrimary" disabled={loading}>{loading ? 'Entrando...' : `Entrar como ${roleTitles[role]}`}</button><button type="button" className="loginSecondary" onClick={() => onLogin({ role, email: email || `${role}@demo.local`, name: name || `${roleTitles[role]} demonstração` })}>Entrar em demonstração</button></div>{msg && <div className="loginMsg">{msg}</div>}</form></div> }
function AuthBar({ auth, onLogout }: { auth: LoginState; onLogout: () => void }) { return <div className="authBar"><strong>{auth.name}</strong><span>Sistema {roleTitles[auth.role]} · {auth.email}</span><button onClick={onLogout}>Sair</button></div> }
function ModeSwitcher({ mode, setMode, role }: { mode: AppMode; setMode: (m: AppMode) => void; role: UserRole }) { if (role === 'store') return <div className="modeSwitch single"><button className="active">Sistema Loja</button></div>; return <div className="modeSwitch"><button className={mode === 'store' ? 'active' : ''} onClick={() => setMode('store')}>Loja</button><button className={mode === 'factory' ? 'active' : ''} onClick={() => setMode('factory')}>Fábrica</button><button className={mode === 'admin' ? 'active' : ''} onClick={() => setMode('admin')}>Técnico</button></div> }
function ModeHelp({ mode }: { mode: AppMode }) { const text = { store: 'Modo comercial: prioriza templates, visual 3D, medidas e preço de venda, sem expor custos internos.', factory: 'Modo produção: prioriza lista técnica, validações, consumo de materiais e plano de corte.', admin: 'Modo técnico: libera catálogo, parâmetros globais, custos e integrações.' }[mode]; return <div className="modeHelp"><b>{modeTitles[mode]}</b><span>{text}</span></div> }
function PanelNav({ panel, setPanel, canManage }: { panel: LeftPanel; setPanel: (p: LeftPanel) => void; canManage: boolean }) { const item = (id: LeftPanel, title: string, sub: string) => <button className={panel === id ? 'active' : ''} onClick={() => setPanel(id)}><b>{title}</b><span>{sub}</span></button>; return <div className="panelNav">{item('templates', 'Templates', 'Modelos prontos')}{item('adjustments', 'Ajustes', 'Medidas e materiais')}{item('project', 'Projeto', 'Objetos e 3D')}{canManage && item('factory', 'Fábrica', 'Produtos e regras')}</div> }
function SectionHero({ eyebrow, title, text }: { eyebrow: string; title: string; text: string }) { return <div className="sectionHero"><span>{eyebrow}</span><h2>{title}</h2><p>{text}</p></div> }
function ProductRegistrationPanel({ onCreate, status }: { onCreate: (draft: ProductDraft) => void; status: string }) { const [draft, setDraft] = React.useState<ProductDraft>({ codigo: '', nome: '', categoria: 'produto', unidade: 'un', custo_fallback: 0, preco_fallback: null, observacoes: '' }); const set = (k: keyof ProductDraft) => (e: any) => setDraft({ ...draft, [k]: k === 'custo_fallback' || k === 'preco_fallback' ? Number(e.target.value || 0) : e.target.value }); return <div className="factoryTool"><h3>Cadastrar produto da fábrica</h3><label>Código<input value={draft.codigo} onChange={set('codigo')} placeholder="Ex: 1036_PRETO" /></label><label>Nome<input value={draft.nome} onChange={set('nome')} placeholder="Ex: Perfil 1036 preto fosco" /></label><div className="actionGrid"><label>Categoria<input value={draft.categoria} onChange={set('categoria')} /></label><label>Unidade<input value={draft.unidade} onChange={set('unidade')} /></label></div><div className="actionGrid"><label>Custo<input type="number" value={draft.custo_fallback} onChange={set('custo_fallback')} /></label><label>Preço venda<input type="number" value={draft.preco_fallback ?? 0} onChange={set('preco_fallback')} /></label></div><label>Observações<input value={draft.observacoes} onChange={set('observacoes')} placeholder="Uso, compatibilidade, regra técnica" /></label><button className="saveBtn" onClick={() => onCreate(draft)}>Salvar produto</button><small>{status}</small></div> }
function Field({ l, v, f }: { l: string; v: number; f: (e: any) => void }) { return <label>{l}<input type="number" value={v} onChange={f} /></label> }
function AmbienteForm({ amb, setAmb, addWindow }: { amb: Amb; setAmb: (a: Amb) => void; addWindow: () => void }) { const fn = (k: keyof Amb) => (e: any) => setAmb({ ...amb, [k]: typeof amb[k] === 'number' ? Number(e.target.value) : e.target.value }); return <div className="formBox"><h2>Ambiente</h2><Field l="Largura ambiente" v={amb.w} f={fn('w')} /><Field l="Profundidade ambiente" v={amb.d} f={fn('d')} /><Field l="Pé-direito" v={amb.h} f={fn('h')} /><label>Material do piso<input value={amb.floor} onChange={fn('floor')} /></label><label className="checkLine"><input type="checkbox" checked={amb.back} onChange={e => setAmb({ ...amb, back: e.target.checked })} /> Parede fundo</label><label className="checkLine"><input type="checkbox" checked={amb.left} onChange={e => setAmb({ ...amb, left: e.target.checked })} /> Parede esquerda</label><label className="checkLine"><input type="checkbox" checked={amb.right} onChange={e => setAmb({ ...amb, right: e.target.checked })} /> Parede direita</label><button className="addBtn" onClick={addWindow}>Janela +</button></div> }
function RuleAlerts({ messages }: { messages: RuleMsg[] }) { return <div className="ruleBox"><h3>Validações técnicas</h3>{messages.length === 0 ? <div className="ruleOk">✓ Sem alertas técnicos</div> : messages.map((m, i) => <div key={i} className={`ruleMsg ${m.severity}`}><b>{ruleIcon(m.severity)} {m.title}</b><span>{m.message}</span></div>)}</div> }
function ObjectList({ objects, selectedId, setSelectedId }: { objects: ProjectObject[]; selectedId: string | null; setSelectedId: (id: string) => void }) { return <div className="paramCard"><h3>Objetos do projeto</h3><button className={selectedId === 'environment' ? 'miniBtn active' : 'miniBtn'} onClick={() => setSelectedId('environment')}>Ambiente</button>{objects.map(o => <button key={o.id} className={selectedId === o.id ? 'miniBtn active' : 'miniBtn'} onClick={() => setSelectedId(o.id)}>{o.visible ? '' : '[oculto] '}{o.name}</button>)}</div> }
function CatalogPanel({ catalog, profiles, materials, status }: { catalog: CatalogItem[]; profiles: ColorProfile[]; materials: ColorMaterial[]; status: string }) { const groups = [...new Set(catalog.map(i => i.categoria))]; const cost = (code: string) => Number(profiles.find(p => (p.nome || '').includes(code))?.custo ?? materials.find(m => (m.nome || '').includes(code))?.custo ?? catalog.find(i => i.codigo === code)?.custo_fallback ?? 0); return <div className="params"><div className="status">{status}</div>{groups.map(g => <div className="paramCard" key={g}><h3>{g}</h3>{catalog.filter(i => i.categoria === g).map(i => <div className="paramRow" key={i.codigo}><span>{i.codigo} — {i.nome}</span><b>{cost(i.codigo) > 0 ? brl(cost(i.codigo)) : 'sem custo'} / {i.unidade}</b></div>)}</div>)}</div> }
function ObjectProps(p: { selectedId: string | null; selected: ProjectObject | null; amb: Amb; setAmb: (a: Amb) => void; updateObj: (id: string, p: any) => void; updateData: (id: string, p: any) => void; duplicate: () => void; remove: () => void; movePreset: (m: string) => void; catalog: CatalogItem[]; profiles: ColorProfile[]; materials: ColorMaterial[]; rows: ParamRow[] }) { if (p.selectedId === 'environment') return <div className="objectBox"><h2>Ambiente selecionado</h2><AmbienteForm amb={p.amb} setAmb={p.setAmb} addWindow={() => { }} /></div>; const o = p.selected; if (!o) return <div className="objectBox"><p>Nenhum objeto selecionado.</p></div>; const base = (k: string) => (e: any) => p.updateObj(o.id, { [k]: k === 'name' ? e.target.value : Number(e.target.value) }); return <div className="objectBox"><h2>{o.name}</h2><label>Nome<input value={o.name} onChange={base('name')} /></label><Field l="Posição X" v={o.x} f={base('x')} /><Field l="Posição Y" v={o.y} f={base('y')} /><Field l="Posição Z" v={o.z} f={base('z')} /><Field l="Rotação" v={o.rotation} f={base('rotation')} /><label className="checkLine"><input type="checkbox" checked={o.visible} onChange={e => p.updateObj(o.id, { visible: e.target.checked })} /> Visível</label><label className="checkLine"><input type="checkbox" checked={o.locked} onChange={e => p.updateObj(o.id, { locked: e.target.checked })} /> Travado</label>{o.type === 'window' && <WindowProps obj={o} updateData={p.updateData} />} {o.type === 'countertop' && <CounterProps obj={o} updateData={p.updateData} />} {o.type === 'closet' && <ClosetProps obj={o} updateData={p.updateData} catalog={p.catalog} profiles={p.profiles} materials={p.materials} />} {o.type === 'cristaleira' && <CristProps obj={o} updateData={p.updateData} rows={p.rows} catalog={p.catalog} profiles={p.profiles} />}<div className="actionGrid"><button className="miniBtn" onClick={p.duplicate}>Duplicar</button><button className="miniBtn" onClick={() => p.updateObj(o.id, { visible: !o.visible })}>{o.visible ? 'Ocultar' : 'Mostrar'}</button><button className="miniBtn" onClick={() => p.movePreset('center')}>Centralizar</button><button className="miniBtn" onClick={() => p.movePreset('back')}>Parede fundo</button><button className="miniBtn" onClick={() => p.movePreset('left')}>Parede esquerda</button><button className="miniBtn" onClick={() => p.movePreset('right')}>Parede direita</button><button className="miniBtn danger" onClick={p.remove}>Deletar</button></div></div> }
function WindowProps({ obj, updateData }: { obj: WinObj; updateData: (id: string, p: any) => void }) { const d = obj.data; const fn = (k: keyof WindowData) => (e: any) => updateData(obj.id, { [k]: typeof d[k] === 'number' ? Number(e.target.value) : e.target.value }); return <div><h3>Janela</h3><Field l="Largura" v={d.w} f={fn('w')} /><Field l="Altura" v={d.h} f={fn('h')} /><Field l="Altura do chão" v={d.fromFloor} f={fn('fromFloor')} /><label>Tipo abertura<select value={d.opening} onChange={fn('opening')}><option value="fixa">Fixa</option><option value="correr">Correr</option><option value="basculante">Basculante</option><option value="abrir">Abrir</option></select></label><label className="checkLine"><input type="checkbox" checked={d.glass} onChange={e => updateData(obj.id, { glass: e.target.checked })} /> Vidro</label><label className="checkLine"><input type="checkbox" checked={d.frame} onChange={e => updateData(obj.id, { frame: e.target.checked })} /> Moldura</label></div> }
function CounterProps({ obj, updateData }: { obj: CounterObj; updateData: (id: string, p: any) => void }) { const d = obj.data; const fn = (k: keyof CounterData) => (e: any) => updateData(obj.id, { [k]: typeof d[k] === 'number' ? Number(e.target.value) : e.target.value }); return <div><h3>Bancada / área molhada</h3><Field l="Largura total" v={d.w} f={fn('w')} /><Field l="Profundidade" v={d.d} f={fn('d')} /><Field l="Espessura" v={d.thick} f={fn('thick')} /><Field l="Altura do chão" v={d.fromFloor} f={fn('fromFloor')} /><Field l="Largura área molhada" v={d.wetW} f={fn('wetW')} /><Field l="Distância da parede" v={d.depthFromWall} f={fn('depthFromWall')} /><label className="checkLine"><input type="checkbox" checked={d.sink} onChange={e => updateData(obj.id, { sink: e.target.checked })} /> Cuba</label><label className="checkLine"><input type="checkbox" checked={d.faucet} onChange={e => updateData(obj.id, { faucet: e.target.checked })} /> Torneira</label></div> }
function ClosetProps({ obj, updateData, catalog, profiles, materials }: { obj: ClosetObj; updateData: (id: string, p: any) => void; catalog: CatalogItem[]; profiles: ColorProfile[]; materials: ColorMaterial[] }) { const d = obj.data, cl = closetCalc(d), rules = closetRules(d, catalog); const fn = (k: keyof ClosetData) => (e: any) => updateData(obj.id, { [k]: typeof d[k] === 'number' ? Number(e.target.value) : e.target.value }); return <div><h3>Closet Evidence</h3><RuleAlerts messages={rules.messages as RuleMsg[]} /><Field l="Largura" v={d.w} f={fn('w')} /><Field l="Profundidade" v={d.d} f={fn('d')} /><Field l="Altura" v={d.h} f={fn('h')} /><Field l="Módulos" v={d.modules} f={fn('modules')} /><Field l="Prateleiras por módulo" v={d.shelves} f={fn('shelves')} /><label>Tipo lateral<select value={d.sideType} onChange={fn('sideType')}><option value="9577 externo">Vidro externo - 9577</option><option value="9571 embutido">Vidro embutido - 9571</option></select></label><label className="checkLine"><input type="checkbox" checked={d.backGlass} onChange={e => updateData(obj.id, { backGlass: e.target.checked })} /> Fundo vidro</label><label className="checkLine"><input type="checkbox" checked={d.doors} onChange={e => updateData(obj.id, { doors: e.target.checked })} /> Portas vidro</label><label className="checkLine"><input type="checkbox" checked={d.led} onChange={e => updateData(obj.id, { led: e.target.checked })} /> LED</label><div className="paramCard"><h3>Prévia técnica</h3><div className="paramRow"><span>Módulo</span><b>{cl.mw.toFixed(0)} mm</b></div><div className="paramRow"><span>Perfis</span><b>{cl.totalProfile.toFixed(2)} m</b></div><div className="paramRow"><span>Vidro</span><b>{cl.glassArea.toFixed(2)} m²</b></div></div></div> }
function CristProps({ obj, updateData, rows, catalog, profiles }: { obj: CristObj; updateData: (id: string, p: any) => void; rows: ParamRow[]; catalog: CatalogItem[]; profiles: ColorProfile[] }) { const d = obj.data, rules = doorRules(d, rows, catalog, profiles); const fn = (k: keyof Config) => (e: any) => updateData(obj.id, { [k]: typeof d[k] === 'number' ? Number(e.target.value) : e.target.value }); return <div><h3>Cristaleira</h3><RuleAlerts messages={rules.messages as RuleMsg[]} /><div className="paramCard"><h3>Medidas pela regra</h3><div className="paramRow"><span>Altura final porta</span><b>{Number(rules.measurements.finalHeight || 0).toFixed(1)} mm</b></div><div className="paramRow"><span>Largura final porta</span><b>{Number(rules.measurements.finalWidth || 0).toFixed(1)} mm</b></div></div><Field l="Altura" v={d.h} f={fn('h')} /><Field l="Largura" v={d.w} f={fn('w')} /><Field l="Profundidade" v={d.d} f={fn('d')} /><Field l="MDF" v={d.mdf} f={fn('mdf')} /><Field l="Prateleiras" v={d.shelves} f={fn('shelves')} /><Field l="Portas" v={d.doors} f={fn('doors')} /><Field l="Margem" v={d.margin} f={fn('margin')} /><label>Perfil 1036<select value={d.profile} onChange={fn('profile')}>{profiles.filter(p => (p.nome || '').includes('1036')).map(p => <option key={p.id} value={p.id}>{p.nome} — {brl(Number(p.custo || 0))}/m</option>)}</select></label><label>Dobradiça<select value={d.hinge} onChange={fn('hinge')}><option value="curva">Curva</option><option value="reta">Reta</option></select></label><label>Vidro<select value={d.glass} onChange={fn('glass')}><option value="incolor">Incolor</option><option value="espelho_prata">Espelho prata</option><option value="reflecta_bronze">Reflecta bronze</option><option value="reflecta_prata">Reflecta prata</option><option value="fume">Fume</option></select></label></div> }
function Parametros({ rows, setRows, saveRows, status }: { rows: ParamRow[]; setRows: (r: ParamRow[]) => void; saveRows: () => void; status: string }) { const edit = (id: string, val: string | boolean) => setRows(rows.map(r => r.id === id ? { ...r, valor_num: r.tipo === 'number' ? Number(val) : r.valor_num, valor_text: r.tipo === 'text' || r.tipo === 'select' ? String(val) : r.valor_text, valor_bool: r.tipo === 'boolean' ? Boolean(val) : r.valor_bool } : r)); const groups = [...new Set(rows.map(r => r.estrutura_slug))]; return <div className="params"><div className="status">{status}</div>{groups.map(g => <div className="paramCard" key={g}><h3>{g}</h3>{rows.filter(r => r.estrutura_slug === g).map(r => <label className="paramEdit" key={r.id}><span>{r.nome}{r.unidade ? ` (${r.unidade})` : ''}</span>{r.tipo === 'boolean' ? <select value={String(r.valor_bool)} onChange={e => edit(r.id, e.target.value === 'true')}><option value="true">Sim</option><option value="false">Não</option></select> : <input type={r.tipo === 'number' ? 'number' : 'text'} step="0.01" value={r.tipo === 'number' ? String(r.valor_num ?? '') : String(r.valor_text ?? '')} onChange={e => edit(r.id, e.target.value)} />}<small>{r.descricao}</small></label>)}</div>)}<button className="saveBtn" onClick={saveRows}>Salvar parâmetros</button></div> }
function Resultado({ mode, amb, objects, rows, profiles, materials, catalog, colorStatus, catalogStatus, tech, cut }: { mode: AppMode; amb: Amb; objects: ProjectObject[]; rows: ParamRow[]; profiles: ColorProfile[]; materials: ColorMaterial[]; catalog: CatalogItem[]; colorStatus: string; catalogStatus: string; tech: any; cut: any }) { return <div className="sideBody resultBody"><h2>{mode === 'store' ? 'Resumo comercial' : mode === 'factory' ? 'Produção' : 'Técnico/Admin'}</h2><p>Ambiente: {amb.w} x {amb.d} x {amb.h} mm</p><p>Objetos: {objects.length}</p>{mode === 'store' && <StoreResult objects={objects} rows={rows} profiles={profiles} materials={materials} />} {mode === 'factory' && <FactoryResult objects={objects} rows={rows} profiles={profiles} materials={materials} catalog={catalog} tech={tech} cut={cut} />} {mode === 'admin' && <AdminResult colorStatus={colorStatus} catalogStatus={catalogStatus} statusLines={[`Parâmetros carregados: ${rows.length}`, `Catálogo MOBIL: ${catalog.length} itens`, `Objetos no projeto: ${objects.length}`]} tech={tech} cut={cut} />}</div> }
function StoreResult({ objects, rows, profiles, materials }: { objects: ProjectObject[]; rows: ParamRow[]; profiles: ColorProfile[]; materials: ColorMaterial[] }) { return <div className="modeResult">{objects.length === 0 && <div className="status">Adicione um template ou estrutura para gerar proposta.</div>}{objects.map(o => { if (o.type === 'cristaleira') { const r = calc(o.data, rows, profiles, materials); return <div className="proposalCard" key={o.id}><b>{o.name}</b><span>{o.data.w} x {o.data.h} x {o.data.d} mm</span><strong>{brl(r.sale)}</strong><small>Preço sugerido comercial</small></div> } if (o.type === 'closet') { const cl = closetCalc(o.data); return <div className="proposalCard" key={o.id}><b>{o.name}</b><span>{o.data.w} x {o.data.d} x {o.data.h} mm</span><strong>{cl.glassArea.toFixed(2)} m² vidro</strong><small>Closet Evidence para proposta</small></div> } if (o.type === 'countertop') return <div className="proposalCard" key={o.id}><b>{o.name}</b><span>{o.data.w} x {o.data.d} mm</span><strong>Área molhada {o.data.wetW} mm</strong></div>; return <div className="proposalCard" key={o.id}><b>{o.name}</b><span>{o.data.w} x {o.data.h} mm</span><strong>Janela no ambiente</strong></div> })}</div> }
function FactoryResult({ objects, rows, profiles, materials, catalog, tech, cut }: { objects: ProjectObject[]; rows: ParamRow[]; profiles: ColorProfile[]; materials: ColorMaterial[]; catalog: CatalogItem[]; tech: any; cut: any }) { return <>{objects.map(o => { if (o.type === 'cristaleira') { const r = calc(o.data, rows, profiles, materials), rules = doorRules(o.data, rows, catalog, profiles); return <p key={o.id}>{o.name}: custo {brl(r.cost)}, venda {brl(r.sale)}, perfil {r.pm.toFixed(2)} m, vidro {r.ga.toFixed(2)} m², alertas {rules.messages.length}</p> } if (o.type === 'closet') { const cl = closetCalc(o.data), rules = closetRules(o.data, catalog); return <p key={o.id}>{o.name}: perfis {cl.totalProfile.toFixed(2)} m, vidro {cl.glassArea.toFixed(2)} m², alertas {rules.messages.length}</p> } if (o.type === 'countertop') return <p key={o.id}>{o.name}: {o.data.w} x {o.data.d} mm, área molhada {o.data.wetW} mm</p>; return <p key={o.id}>{o.name}: {o.data.w} x {o.data.h} mm</p> })}<MdfCutPanel cut={cut} /><ProductionPanel tech={tech} /></> }
function AdminResult({ colorStatus, catalogStatus, statusLines, tech, cut }: { colorStatus: string; catalogStatus: string; statusLines: string[]; tech: any; cut: any }) { return <><div className="status">{catalogStatus}</div><div className="status">{colorStatus}</div>{statusLines.map(line => <div className="paramRow" key={line}><span>{line}</span><b>ok</b></div>)}<ProductionPanel tech={tech} /><MdfCutPanel cut={cut} /></> }
function ProductionPanel({ tech }: { tech: any }) { const groups = Object.entries((tech.lines || []).reduce((a: any, l: any) => { (a[l.grupo] ||= []).push(l); return a }, {})); const copy = () => navigator.clipboard?.writeText(formatTechnicalList(tech)); return <div className="techPanel"><div className="techHead"><div><h2>Lista técnica</h2><span>Produção, custo e insumos</span></div><button className="copyBtn" onClick={copy}>Copiar</button></div><div className="techTotals"><div><span>Custo total</span><b>{brl(tech.totalCost || 0)}</b></div><div><span>Venda sugerida</span><b>{brl(tech.suggestedPrice || 0)}</b></div></div>{groups.map(([g, lines]: any) => <div className="techGroup" key={g}><h3>{String(g).toUpperCase()}</h3>{lines.map((l: any, i: number) => <div className="techLine" key={g + i}><div><b>{l.codigo} — {l.nome}</b><span>{l.objeto} · {l.medida}</span></div><div><b>{Number(l.qtd).toFixed(l.unidade === 'un' ? 0 : 2)} {l.unidade}</b><span>{brl(l.custoTotal)} {l.found ? '' : '⚠'}</span></div></div>)}</div>)}</div> }
function MdfCutPanel({ cut }: { cut: any }) { const copy = () => navigator.clipboard?.writeText(formatMdfCutPlan(cut)); return <div className="cutPanel"><div className="techHead"><div><h2>Plano de corte MDF CNC</h2><span>Chapa 2750 x 1850 mm · coordenadas X/Y</span></div><button className="copyBtn" onClick={copy}>Copiar CNC</button></div><div className="techTotals"><div><span>Área MDF</span><b>{Number(cut.totalArea || 0).toFixed(2)} m²</b></div><div><span>Chapas</span><b>{cut.sheets?.length || 0}</b></div></div>{cut.warnings?.map((w: string, i: number) => <div className="ruleMsg warning" key={i}><b>⚠ Atenção</b><span>{w}</span></div>)}{cut.sheets?.map((s: any) => <div className="sheetCard" key={s.sheet}><div className="sheetTitle"><b>Chapa {s.sheet}</b><span>Aproveitamento {Number(s.efficiency).toFixed(1)}%</span></div><div className="sheetCanvas">{s.parts.map((p: any, i: number) => <div key={p.id} className="cutPiece" style={{ left: `${p.x / s.w * 100}%`, top: `${p.y / s.h * 100}%`, width: `${p.cutW / s.w * 100}%`, height: `${p.cutH / s.h * 100}%` }} title={`${p.nome} ${p.cutW}x${p.cutH}`}><b>{i + 1}</b><span>{p.cutW.toFixed(0)}x{p.cutH.toFixed(0)}</span></div>)}</div>{s.parts.map((p: any, i: number) => <div className="techLine" key={p.id}><div><b>{i + 1}. {p.nome}</b><span>{p.objeto} · X {p.x.toFixed(0)} · Y {p.y.toFixed(0)} · {p.edge || 'sem fita'}</span></div><div><b>{p.cutW.toFixed(0)} x {p.cutH.toFixed(0)}</b><span>{p.rotated ? 'girada' : 'normal'}</span></div></div>)}</div>)}</div> }
function Object3D({ obj, selected, onSelect, amb, rows, profiles, materials }: { obj: ProjectObject; selected: boolean; onSelect: () => void; amb: Amb; rows: ParamRow[]; profiles: ColorProfile[]; materials: ColorMaterial[] }) { if (!obj.visible) return null; const rot = obj.rotation * Math.PI / 180; return <group position={[obj.x / 1000, obj.y / 1000, obj.z / 1000]} rotation={[0, rot, 0]} onPointerDown={(e: any) => { e.stopPropagation(); onSelect() }}>{obj.type === 'window' && <Window3D obj={obj} amb={amb} selected={selected} />} {obj.type === 'countertop' && <Counter3D obj={obj} amb={amb} selected={selected} />} {obj.type === 'closet' && <Closet3D data={obj.data} selected={selected} />} {obj.type === 'cristaleira' && <Cabinet3D data={obj.data} r={calc(obj.data, rows, profiles, materials)} selected={selected} />}</group> }
function Env3D({ amb, selected, onSelect }: { amb: Amb; selected: boolean; onSelect: () => void }) { const w = amb.w / 1000, d = amb.d / 1000, h = amb.h / 1000; return <group onPointerDown={(e: any) => { e.stopPropagation(); onSelect() }}><Box p={[0, -.015, 0]} z={[w, .03, d]} color={selected ? '#4b4b4b' : '#383838'} /><gridHelper args={[Math.max(w, d), 12]} />{amb.back && <Box p={[0, h / 2, -d / 2]} z={[w, h, .04]} color="#d8d8d8" opacity={.72} />} {amb.left && <Box p={[-w / 2, h / 2, 0]} z={[.04, h, d]} color="#cfcfcf" opacity={.72} />} {amb.right && <Box p={[w / 2, h / 2, 0]} z={[.04, h, d]} color="#cfcfcf" opacity={.72} />}</group> }
function Window3D({ obj, amb, selected }: { obj: WinObj; amb: Amb; selected: boolean }) { const d = amb.d / 1000, w = obj.data.w / 1000, h = obj.data.h / 1000, y = obj.data.fromFloor / 1000 + h / 2, z = -d / 2 + .035, b = .035; return <group position={[0, y, z]}>{obj.data.glass && <Box p={[0, 0, 0]} z={[w, h, .018]} color={selected ? '#69b7ff' : '#77aacc'} opacity={.55} />} {obj.data.frame && <><Box p={[0, h / 2 - b / 2, .012]} z={[w, b, .035]} color={selected ? '#ffcc33' : '#222'} /><Box p={[0, -h / 2 + b / 2, .012]} z={[w, b, .035]} color={selected ? '#ffcc33' : '#222'} /><Box p={[-w / 2 + b / 2, 0, .012]} z={[b, h, .035]} color={selected ? '#ffcc33' : '#222'} /><Box p={[w / 2 - b / 2, 0, .012]} z={[b, h, .035]} color={selected ? '#ffcc33' : '#222'} /></>}</group> }
function Counter3D({ obj, amb, selected }: { obj: CounterObj; amb: Amb; selected: boolean }) { const c = obj.data, total = c.w / 1000, dep = c.d / 1000, th = c.thick / 1000, wet = Math.min(c.wetW, c.w) / 1000, left = (total - wet) / 2, y = c.fromFloor / 1000 + th / 2, z = -amb.d / 2000 + c.depthFromWall / 1000 + dep / 2; return <group position={[0, y, z]}><Box p={[-wet / 2 - left / 2, 0, 0]} z={[left, th, dep]} color={selected ? '#c9c9c9' : '#aaaaaa'} /><Box p={[0, 0, 0]} z={[wet, th, dep]} color={selected ? '#92b5c4' : '#7f8f98'} /><Box p={[wet / 2 + left / 2, 0, 0]} z={[left, th, dep]} color={selected ? '#c9c9c9' : '#aaaaaa'} />{c.sink && <Box p={[0, th / 2 + .006, 0]} z={[wet * .55, .012, dep * .45]} color="#141414" />}{c.faucet && <><Box p={[0, th / 2 + .13, -dep * .18]} z={[.035, .24, .035]} color="#c9c9c9" /><Box p={[0, th / 2 + .23, -dep * .08]} z={[.035, .035, .2]} color="#c9c9c9" /></>}</group> }
function Closet3D({ data, selected }: { data: ClosetData; selected: boolean }) { const w = data.w / 1000, d = data.d / 1000, h = data.h / 1000, m = Math.max(1, data.modules), mw = w / m, b = .035, rail = .045; return <group position={[0, h / 2, 0]}><Box p={[0, h / 2 - rail / 2, 0]} z={[w, rail, d]} color={selected ? '#222' : '#111'} /><Box p={[0, -h / 2 + rail / 2, 0]} z={[w, rail, d]} color={selected ? '#222' : '#111'} /><Box p={[0, 0, -d / 2 + rail / 2]} z={[w, rail, rail]} color="#111" />{Array.from({ length: m + 1 }).map((_, i) => <Box key={i} p={[-w / 2 + i * mw, 0, 0]} z={[b, h, d]} color={selected ? '#222' : '#050505'} />)}{Array.from({ length: m }).map((_, i) => <group key={i} position={[-w / 2 + mw / 2 + i * mw, 0, 0]}>{Array.from({ length: data.shelves }).map((_, j) => <Box key={j} p={[0, -h / 2 + (j + 1) * h / (data.shelves + 1), 0]} z={[mw - .05, .025, d - .08]} color="#b6864a" />)}{data.led && <Box p={[0, h / 2 - .08, -d / 2 + .06]} z={[mw - .08, .018, .018]} color="#f8e6a5" />}{data.doors && <Door x={0} w={mw - .035} h={h - .08} z={d / 2 + .025} />}</group>)}{data.backGlass && <Box p={[0, 0, -d / 2 + .02]} z={[w - .08, h - .08, .018]} color="#88aacc" opacity={.22} />}</group> }
function Cabinet3D({ data, r, selected }: { data: Config; r: ReturnType<typeof calc>; selected: boolean }) { const w = data.w / 1000, h = data.h / 1000, d = data.d / 1000, m = data.mdf / 1000, uw = r.uw / 1000, uh = r.uh / 1000, bw = r.baseW / 1000, dw = r.dw / 1000, dh = r.dh / 1000, side = r.sideGap / 1000, gap = r.displayGap / 1000; return <group position={[0, h / 2, 0]}><Box p={[-w / 2 + m / 2, 0, 0]} z={[m, h, d]} color={selected ? '#a46f44' : '#7a5232'} /><Box p={[w / 2 - m / 2, 0, 0]} z={[m, h, d]} color={selected ? '#a46f44' : '#7a5232'} /><Box p={[0, h / 2 - m / 2, 0]} z={[w, m, d]} color="#7a5232" /><Box p={[0, -h / 2 + m / 2, 0]} z={[w, m, d]} color="#7a5232" />{Array.from({ length: data.shelves }).map((_, i) => <Box key={i} p={[0, -uh / 2 + (i + 1) * uh / (data.shelves + 1), 0]} z={[uw, m, d - m]} color="#8b623e" />)}{Array.from({ length: data.doors }).map((_, i) => <Door key={i} x={-bw / 2 + side + dw / 2 + i * (dw + gap)} w={dw} h={dh} z={d / 2 + .02} />)}</group> }
function Door({ x, w, h, z }: { x: number; w: number; h: number; z: number }) { const b = .035; return <group position={[x, 0, z]}><Box p={[0, 0, 0]} z={[w - b * 2, h - b * 2, .01]} color="#7f5a35" opacity={.45} /><Box p={[0, h / 2 - b / 2, .01]} z={[w, b, .03]} color="#050505" /><Box p={[0, -h / 2 + b / 2, .01]} z={[w, b, .03]} color="#050505" /><Box p={[-w / 2 + b / 2, 0, .01]} z={[b, h, .03]} color="#050505" /><Box p={[w / 2 - b / 2, 0, .01]} z={[b, h, .03]} color="#050505" /></group> }
function Box({ p, z, color, opacity = 1 }: { p: [number, number, number]; z: [number, number, number]; color: string; opacity?: number }) { return <mesh position={p}><boxGeometry args={z} /><meshStandardMaterial color={color} transparent={opacity < 1} opacity={opacity} /></mesh> }
createRoot(document.getElementById('root') as HTMLElement).render(<React.StrictMode><App /></React.StrictMode>);
